    for (int i = 0; i < n; ++i) {
        if (notes[i] == 5) {
            ++fiveCount;
        } else if (notes[i] == 10) {
            if (fiveCount > 0) {
                --fiveCount;
                ++tenCount;
            } else {
                return false;
            }
        } else {
            if (fiveCount > 0 && tenCount > 0) {
                --fiveCount;
                --tenCount;
            } else if (fiveCount >= 3) {
                fiveCount -= 3;
            } else {
                return false;
            }
        }
    }
    return true;
}

