bool isPossible ( int n , int index , int modulo , int M , int * arr , bool ** dp ) {
  modulo = ( ( modulo % M ) + M ) % M ;
  if ( index == n ) {
    if ( modulo == 0 ) {
      return true ;
    }
    return false ;
  }
  if ( dp [ index ] [ modulo ] != - 1 ) {
    return dp [ index ] [ modulo ] ;
  }
  bool placeAdd = isPossible ( n , index + 1 , modulo + arr [ index ] , M , arr , dp ) ;
  bool placeMinus = isPossible ( n , index + 1 , modulo - arr [ index ] , M , arr , dp ) ;
  bool res = ( placeAdd || placeMinus ) ;
  dp [ index ] [ modulo ] = res ;
  return res ;
}

