    int Integral = static_cast<int>(num);
    double fractional = num - static_cast<double>(Integral);
    while (Integral > 0) {
        int rem = Integral % 2;
        binary += to_string(rem);
        Integral /= 2;
    }
    reverse(binary.begin(), binary.end());
    binary += '.';
    while (k_prec > 0) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= static_cast<double>(fract_bit);
            binary += '1';
        } else {
            binary += '0';
        }
        k_prec--;
    }
    return binary;
}

