int binaryMedian(std::vector<std::vector<int>>& matrix, int rows, int cols) {
    int min = std::numeric_limits<int>::max();
    int max = std::numeric_limits<int>::min();
    for (int i = 0; i < rows; ++i) {
        if (matrix[i][0] < min) {
            min = matrix[i][0];
        }
        if (matrix[i][cols - 1] > max) {
            max = matrix[i][cols - 1];
        }
    }
    int desired = (rows * cols + 1) / 2;
    while (min < max) {
        int mid = min + (max - min) / 2;
        int place = 0;
        for (int i = 0; i < rows; ++i) {
            auto it = std::upper_bound(matrix[i].begin(), matrix[i].end(), mid);
            place += std::distance(matrix[i].begin(), it);
        }
        if (place < desired) {
            min = mid + 1;
        } else {
            max = mid;
        }
    }
    std::cout << "Median is " << min << std::endl;
    return min;
}

