int find_maximum(const std::vector<int>& a, int n, int k) {
    std::unordered_map<int, int> b;
    for (int i = 0; i < n; ++i) {
        int x = a[i];
        int d = std::min(1 + i, n - i);
        auto it = b.find(x);
        if (it == b.end()) {
            b[x] = d;
        } else {
            it->second = std::min(d, it->second);
        }
    }
    int ans = std::numeric_limits<int>::max();
    for (int i = 0; i < n; ++i) {
        int x = a[i];
        if (x != (k - x) && b.count(k - x)) {
            ans = std::min(std::max(b[x], b[k - x]), ans);
        }
    }
    return ans;
}

