double seriesSum(int n) {
    double res = 0.0;
    bool sign = true;
    for (int i = 1; n > 0; n--, i += 2) {
        if (sign) {
            sign = false;
            res += static_cast<double>(i + 1) / static_cast<double>(i + 2);
        } else {
            sign = true;
            res -= static_cast<double>(i + 1) / static_cast<double>(i + 2);
        }
    }
    return res;
}

