std::string findSum(std::string str1, std::string str2) {
    if (str1.length() > str2.length()) {
        std::swap(str1, str2);
    }
    std::string str = "";
    int n1 = str1.length();
    int n2 = str2.length();
    std::reverse(str1.begin(), str1.end());
    std::reverse(str2.begin(), str2.end());
    int carry = 0;
    for (int i = 0; i < n1; ++i) {
        int sum = ((str1[i] - '0') + ((str2[i] - '0') + carry));
        if (sum < 0) {
            str += char(sum % -10 + '0');
        } else {
            str += char(sum % 10 + '0');
        }
        carry = sum / 10;
    }
    for (int i = n1; i < n2; ++i) {
        int sum = ((str2[i] - '0') + carry);
        if (sum < 0) {
            str += char(sum % -10 + '0');
        } else {
            str += char(sum % 10 + '0');
        }
        carry = sum / 10;
    }
    if (carry) {
        str += char(carry + '0');
    }
    std::reverse(str.begin(), str.end());
    return str;
}

