int countTransformation(std::string a, std::string b) {
    int n = a.length();
    int m = b.length();
    if (m == 0) {
        return 1;
    }
    std::vector<std::vector<int>> dp(m, std::vector<int>(n, 0));
    for (int i = 0; i < m; i++) {
        for (int j = i; j < n; j++) {
            if (i == 0) {
                if (j == 0) {
                    dp[i][j] = (a[j] == b[i]) ? 1 : 0;
                } else {
                    dp[i][j] = dp[i][j - 1] + ((a[j] == b[i]) ? 1 : 0);
                }
            } else {
                dp[i][j] = dp[i][j - 1] + ((a[j] == b[i]) ? dp[i - 1][j - 1] : 0);
            }
        }
    }
    return dp[m - 1][n - 1];
}

